#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define PI 3.14159265358979323846
#define EPS 1e-9

// Structure to represent a point
typedef struct {
    double x, y;
} Point;

// Function to calculate the orientation of three points
int orientation(Point p, Point q, Point r) {
    double val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (fabs(val) < EPS) return 0; // Collinear
    return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
}

// Function to calculate the convex hull using Graham scan
void convexHull(Point points[], int n, Point hull[]) {
    int l = 0;
    for (int i = 1; i < n; i++) {
        if (points[i].x < points[l].x) l = i;
    }

    int p = l, q;
    do {
        hull[p] = points[l];
        q = (p + 1) % n;

        for (int i = 0; i < n; i++) {
            if (orientation(points[l], points[i], points[q]) == 2) {
                q = i;
            }
        }
        p = q;
        l++;
    } while (p != l);
}

// Function to calculate the area of a polygon
double polygonArea(Point points[], int n) {
    double area = 0.0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += points[i].x * points[j].y;
        area -= points[j].x * points[i].y;
    }
    area = fabs(area) / 2.0;
    return area;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        Point points[n];
        for (int i = 0; i < n; i++) {
            scanf("%lf %lf", &points[i].x, &points[i].y);
        }

        Point hull[n];
        convexHull(points, n, hull);
        double maxArea = 0.0;
        for (int i = 0; i < n; i++) {
            Point temp[n - 1];
            int j = 0;
            for (int k = 0; k < n; k++) {
                if (k != i) {
                    temp[j++] = points[k];
                }
            }
            double area = polygonArea(temp, n - 1);
            maxArea = fmax(maxArea, area);
        }
        printf("%.0lf\n", maxArea * 2);
    }
    return 0;
}

