#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
using namespace std;

struct Point {
    long long x, y;
};

long long crossProduct(Point p, Point q, Point r) {
    return (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
}

vector<Point> convexHull(vector<Point> points) {
    int n = points.size();
    if (n < 3) return {};

    int l = 0;
    for (int i = 1; i < n; i++) {
        if (points[i].x < points[l].x) l = i;
    }

    vector<Point> hull;
    int p = l;
    do {
        hull.push_back(points[p]);
        int q = (p + 1) % n;

        for (int i = 0; i < n; i++) {
            if (crossProduct(points[p], points[i], points[q]) > 0) {
                q = i;
            }
        }
        p = q;
    } while (p != l);
    return hull;
}

long long polygonArea(vector<Point> points) {
    int n = points.size();
    long long area = 0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += points[i].x * points[j].y;
        area -= points[j].x * points[i].y;
    }
    return abs(area) / 2;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<Point> points(n);
        for (int i = 0; i < n; i++) {
            cin >> points[i].x >> points[i].y;
        }

        vector<Point> hull = convexHull(points);
        long long maxArea = 0;
        for (int i = 0; i < n; i++) {
            vector<Point> temp;
            for (int j = 0; j < n; j++) {
                if (j != i) temp.push_back(points[j]);
            }
            long long area = polygonArea(temp);
            maxArea = max(maxArea, area);
        }
        cout << maxArea * 2 << endl;
    }
    return 0;
}

