import java.util.Scanner;
import java.util.ArrayList;
public class Main {
    static class Point {
        long x, y;
        Point(long x, long y) {
            this.x = x;
            this.y = y;
        }
    }

    public static long crossProduct(Point p, Point q, Point r) {
        return (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    }

    public static ArrayList<Point> convexHull(ArrayList<Point> points) {
        int n = points.size();
        if (n < 3) return new ArrayList<>();

        int l = 0;
        for (int i = 1; i < n; i++) {
            if (points.get(i).x < points.get(l).x) l = i;
        }

        ArrayList<Point> hull = new ArrayList<>();
        int p = l;
        do {
            hull.add(points.get(p));
            int q = (p + 1) % n;

            for (int i = 0; i < n; i++) {
                if (crossProduct(points.get(p), points.get(i), points.get(q)) > 0) {
                    q = i;
                }
            }
            p = q;
        } while (p != l);
        return hull;
    }

    public static long polygonArea(ArrayList<Point> points) {
        int n = points.size();
        long area = 0;
        for (int i = 0; i < n; i++) {
            int j = (i + 1) % n;
            area += points.get(i).x * points.get(j).y;
            area -= points.get(j).x * points.get(i).y;
        }
        return Math.abs(area) / 2;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            ArrayList<Point> points = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                long x = sc.nextLong();
                long y = sc.nextLong();
                points.add(new Point(x, y));
            }

            ArrayList<Point> hull = convexHull(points);
            long maxArea = 0;
            for (int i = 0; i < n; i++) {
                ArrayList<Point> temp = new ArrayList<>();
                for (int j = 0; j < n; j++) {
                    if (j != i) temp.add(points.get(j));
                }
                long area = polygonArea(temp);
                maxArea = Math.max(maxArea, area);
            }
            System.out.println(maxArea * 2);
        }
    }
}

